## Step 5: Create `packages/rest-api-client-generator/src/type-mapper.ts`

This module converts a DMMF field's `kind` + `type` to a TypeScript type string. It is a pure function with no side effects, making it easy to unit-test in isolation.

```typescript
import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a DMMF scalar type name to its TypeScript equivalent.
 * Returns `null` if the type is not a known scalar (i.e., it is an enum or
 * object reference, which the caller handles separately).
 */
export function scalarToTsType(dmmfType: string): string {
  switch (dmmfType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      // JSON cannot represent BigInt; serialise as string over the wire
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      // ISO 8601 string
      return 'string'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      // base64-encoded string over the wire
      return 'string'
    case 'Decimal':
      // Decimal.js serialises to string in JSON
      return 'string'
    default:
      // Unknown scalars fall back to unknown
      return 'unknown'
  }
}

/**
 * Resolves the TypeScript type string for a DMMF field, including list and
 * nullability wrappers.  Relation (object) fields are typed as the related
 * model interface name.
 *
 * @param field        - The DMMF field being mapped
 * @param inInputType  - When true we are generating an input/param type, which
 *                       means relation fields are skipped (returns null) because
 *                       they are not part of REST payloads in CRUD inputs.
 */
export function fieldToTsType(field: DMMF.Field, inInputType = false): string | null {
  let baseType: string

  switch (field.kind) {
    case 'scalar':
      baseType = scalarToTsType(field.type)
      break
    case 'enum':
      // Reference the generated enum type by name
      baseType = field.type
      break
    case 'object':
      if (inInputType) {
        // Relation fields are not part of scalar create/update inputs
        return null
      }
      // In the model interface, relation fields are optional references
      baseType = field.type
      break
    case 'unsupported':
      baseType = 'unknown'
      break
    default:
      baseType = 'unknown'
  }

  // Apply list wrapper first, then nullability
  const listWrapped = field.isList ? `${baseType}[]` : baseType

  // If the field is not required (nullable), add `| null`
  if (!field.isRequired) {
    return `${listWrapped} | null`
  }

  return listWrapped
}
```

