## Step 6: Create `packages/rest-api-client-generator/src/generate-rest-client.ts`

This is the core of the generator. It takes `DMMF.Document`, builds three files as strings, and writes them to the output directory.

### Helper: `getWhereUniqueFields`

```typescript
/**
 * Returns the list of field names that identify a unique record for a model.
 * Priority:
 *   1. The single @id field (most common case)
 *   2. A composite primary key (@@id) — all its constituent fields
 *   3. All @unique scalar fields (fallback for models with no @id)
 */
function getWhereUniqueFields(model: DMMF.Model): string[] {
  // Single @id field
  const idField = model.fields.find((f) => f.isId)
  if (idField) return [idField.name]

  // Composite @@id
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    return model.primaryKey.fields
  }

  // Fall back to all @unique scalar fields
  return model.fields.filter((f) => f.isUnique && f.kind === 'scalar').map((f) => f.name)
}
```

### Helper: `isAutoGeneratedField`

A field should be excluded from `CreateInput` (it is auto-managed by the database/Prisma):

```typescript
function isAutoGeneratedField(field: DMMF.Field): boolean {
  // Fields marked @updatedAt are set automatically by Prisma
  if (field.isUpdatedAt) return true
  // Fields marked @default(autoincrement()), @default(uuid()), etc.
  // i.e., id fields with a DB-side default
  if (field.isId && field.hasDefaultValue) return true
  // Fields explicitly marked as generated (e.g., generated columns)
  if (field.isGenerated) return true
  return false
}
```

### `generateModelsTs(dmmf)` → `string`

Generates `models.ts`:
- One TypeScript `export type` alias per enum (as a union of string literals, simple and portable)
- One `export interface` per model with all fields

```typescript
function generateModelsTs(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push('// This file is auto-generated by @prisma/rest-api-client-generator.')
  lines.push('// Do not edit manually.')
  lines.push('')

  // ── Enums ──────────────────────────────────────────────────────────────────
  for (const enumDef of dmmf.datamodel.enums) {
    const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
    lines.push(`export type ${enumDef.name} = ${values}`)
    lines.push('')
  }

  // ── Model interfaces ───────────────────────────────────────────────────────
  for (const model of dmmf.datamodel.models) {
    lines.push(`export interface ${model.name} {`)
    for (const field of model.fields) {
      const tsType = fieldToTsType(field, false /* in model interface */)
      if (tsType === null) continue // should never happen in model interface mode

      // Relation (object) fields are optional — they may or may not be
      // included in the REST response depending on whether the consumer
      // asked for them.
      const optional = field.kind === 'object' || !field.isRequired

      lines.push(`  ${field.name}${optional ? '?' : ''}: ${tsType}`)
    }
    lines.push('}')
    lines.push('')
  }

  return lines.join('\n')
}
```

### `generateClientTs(dmmf)` → `string`

Generates `client.ts` with:
1. Input/param types for each model
2. The `PrismaRestApiClient` class

#### Input type naming convention

| Type                    | Generated name               |
|-------------------------|------------------------------|
| Create payload          | `UserCreateInput`            |
| Update payload          | `UserUpdateInput`            |
| Where-unique identifier | `UserWhereUniqueInput`       |
| findMany params         | `UserFindManyParams`         |

#### `CreateInput` rules
- Scalar fields only (`kind !== 'object'`)
- Fields that are auto-generated (`isAutoGeneratedField`) → `fieldName?: TsType` (optional)
- Nullable fields (`!isRequired`) → `fieldName?: TsType | null` (optional)
- Required scalar fields without defaults → `fieldName: TsType` (required)

#### `UpdateInput` rules
- All scalar fields are optional (PATCH semantics — only provide what changes)
- Same type resolution as `CreateInput`, just every field gets `?:`

#### `WhereUniqueInput` rules
- Only the identifying fields, all optional in the type (intersection handled at runtime)
- Uses `getWhereUniqueFields` result

#### `FindManyParams` rules
- `skip?: number`
- `take?: number`
- `where?: Partial<ModelName>` — using the model interface itself for filtering
- `orderBy?: Partial<Record<keyof ModelName, 'asc' | 'desc'>>`

```typescript
function generateClientTs(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push('// This file is auto-generated by @prisma/rest-api-client-generator.')
  lines.push('// Do not edit manually.')
  lines.push('')
  lines.push("import type { ")

  // Import all model and enum names from models.ts
  const typeNames = [
    ...dmmf.datamodel.enums.map((e) => e.name),
    ...dmmf.datamodel.models.map((m) => m.name),
  ]
  lines.push(`import type { ${typeNames.join(', ')} } from './models'`)
  lines.push('')

  // ── Per-model input types ──────────────────────────────────────────────────
  for (const model of dmmf.datamodel.models) {
    const scalarFields = model.fields.filter(
      (f) => f.kind !== 'object' && !isAutoGeneratedField(f)
    )

    // CreateInput
    lines.push(`export interface ${model.name}CreateInput {`)
    for (const field of scalarFields) {
      const tsType = fieldToTsType(field, true)!
      const optional = !field.isRequired || field.hasDefaultValue
      lines.push(`  ${field.name}${optional ? '?' : ''}: ${tsType}`)
    }
    lines.push('}')
    lines.push('')

    // UpdateInput — all fields optional (PATCH semantics)
    lines.push(`export interface ${model.name}UpdateInput {`)
    for (const field of scalarFields) {
      const tsType = fieldToTsType(field, true)!
      lines.push(`  ${field.name}?: ${tsType}`)
    }
    lines.push('}')
    lines.push('')

    // WhereUniqueInput — identifying fields
    const uniqueFieldNames = getWhereUniqueFields(model)
    const uniqueFields = model.fields.filter((f) => uniqueFieldNames.includes(f.name))
    lines.push(`export interface ${model.name}WhereUniqueInput {`)
    for (const field of uniqueFields) {
      const tsType = fieldToTsType(field, true)!
      // All optional so callers can provide a subset for partial composite keys,
      // though in practice all fields in the composite must be supplied at runtime
      lines.push(`  ${field.name}?: ${tsType}`)
    }
    lines.push('}')
    lines.push('')

    // FindManyParams
    lines.push(`export interface ${model.name}FindManyParams {`)
    lines.push(`  skip?: number`)
    lines.push(`  take?: number`)
    lines.push(`  where?: Partial<${model.name}>`)
    lines.push(`  orderBy?: Partial<Record<keyof ${model.name}, 'asc' | 'desc'>>`)
    lines.push('}')
    lines.push('')
  }

  // ── PrismaRestApiClient ───────────────────────────────────────────────────
  lines.push('export class PrismaRestApiClient {')
  lines.push("  readonly #baseUrl: string")
  lines.push("  readonly #headers: Record<string, string>")
  lines.push('')
  lines.push('  constructor(options: { baseUrl: string; headers?: Record<string, string> }) {')
  lines.push('    this.#baseUrl = options.baseUrl.replace(/\\/$/, \'\')')
  lines.push('    this.#headers = { \'Content-Type\': \'application/json\', ...options.headers }')
  lines.push('  }')
  lines.push('')
  lines.push('  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {')
  lines.push('    const url = `${this.#baseUrl}${path}`')
  lines.push('    const response = await fetch(url, {')
  lines.push('      method,')
  lines.push('      headers: this.#headers,')
  lines.push('      body: body !== undefined ? JSON.stringify(body) : undefined,')
  lines.push('    })')
  lines.push('    if (!response.ok) {')
  lines.push('      throw new Error(`REST API error ${response.status}: ${await response.text()}`)')
  lines.push('    }')
  lines.push('    return response.json() as Promise<T>')
  lines.push('  }')
  lines.push('')

  // Per-model CRUD methods
  for (const model of dmmf.datamodel.models) {
    const resource = toKebabCase(model.name) // e.g., "BlogPost" → "blog-post"

    // findMany
    lines.push(`  async ${lcFirst(model.name)}FindMany(params?: ${model.name}FindManyParams): Promise<${model.name}[]> {`)
    lines.push(`    const query = params ? '?' + new URLSearchParams(flattenParams(params)).toString() : ''`)
    lines.push(`    return this.#request<${model.name}[]>('GET', \`/${resource}\${query}\`)`)
    lines.push('  }')
    lines.push('')

    // findUnique — builds path segment from WhereUniqueInput
    lines.push(`  async ${lcFirst(model.name)}FindUnique(where: ${model.name}WhereUniqueInput): Promise<${model.name} | null> {`)
    lines.push(`    const id = extractId(where)`)
    lines.push(`    return this.#request<${model.name} | null>('GET', \`/${resource}/\${id}\`)`)
    lines.push('  }')
    lines.push('')

    // create
    lines.push(`  async ${lcFirst(model.name)}Create(data: ${model.name}CreateInput): Promise<${model.name}> {`)
    lines.push(`    return this.#request<${model.name}>('POST', '/${resource}', data)`)
    lines.push('  }')
    lines.push('')

    // update
    lines.push(`  async ${lcFirst(model.name)}Update(where: ${model.name}WhereUniqueInput, data: ${model.name}UpdateInput): Promise<${model.name}> {`)
    lines.push(`    const id = extractId(where)`)
    lines.push(`    return this.#request<${model.name}>('PATCH', \`/${resource}/\${id}\`, data)`)
    lines.push('  }')
    lines.push('')

    // delete
    lines.push(`  async ${lcFirst(model.name)}Delete(where: ${model.name}WhereUniqueInput): Promise<${model.name}> {`)
    lines.push(`    const id = extractId(where)`)
    lines.push(`    return this.#request<${model.name}>('DELETE', \`/${resource}/\${id}\`)`)
    lines.push('  }')
    lines.push('')
  }

  lines.push('}')
  lines.push('')

  // ── Private helpers (not exported, minimal bundle) ────────────────────────
  lines.push('function extractId(where: Record<string, unknown>): string {')
  lines.push('  const values = Object.values(where).filter((v) => v !== undefined)')
  lines.push('  if (values.length === 0) throw new Error(\'WhereUniqueInput must have at least one field set\')')
  lines.push('  if (values.length === 1) return String(values[0])')
  lines.push('  // Composite key: serialize as JSON for the URL segment')
  lines.push('  return encodeURIComponent(JSON.stringify(where))')
  lines.push('}')
  lines.push('')
  lines.push('function flattenParams(obj: Record<string, unknown>): Record<string, string> {')
  lines.push('  const out: Record<string, string> = {}')
  lines.push('  for (const [key, value] of Object.entries(obj)) {')
  lines.push('    if (value !== undefined) {')
  lines.push('      out[key] = typeof value === \'object\' ? JSON.stringify(value) : String(value)')
  lines.push('    }')
  lines.push('  }')
  lines.push('  return out')
  lines.push('}')

  return lines.join('\n')
}
```

