## Step 7: Create `packages/rest-api-client-generator/src/generator.ts`

This follows exactly the same shape as `PrismaClientTsGenerator`.

The generator uses a simple default output: `./generated/rest-client` relative to the directory containing the schema file. If `config.output` is set, it uses that instead. Unlike `client-generator-ts`, this generator does not throw if output is missing — it falls back to the default.

```typescript
import path from 'node:path'

import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateRestClient } from './generate-rest-client'

const DEFAULT_OUTPUT = './generated/rest-client'

function getOutputPath(config: GeneratorConfig): string {
  if (config.output) {
    return parseEnvValue(config.output)
  }
  // Fall back to a path relative to the schema file location
  return path.resolve(path.dirname(config.sourceFilePath), DEFAULT_OUTPUT)
}

export class RestApiClientGenerator implements Generator {
  readonly name = 'prisma-rest-api-client'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      defaultOutput: DEFAULT_OUTPUT,
      prettyName: 'Prisma REST API Client',
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = getOutputPath(options.generator)

    await generateRestClient({
      dmmf: options.dmmf,
      outputDir,
    })
  }
}
```

Key design decisions:
- `name = 'prisma-rest-api-client'` is what users write as `provider = "prisma-rest-api-client"` in their schema.
- `requiresEngines: []` (not set, defaults to none) — this generator requires no query or migration engine.
- `version` is not set in the manifest — this avoids requiring a version sync with engines.
- `getOutputPath` resolves the default output relative to `config.sourceFilePath` (the `.prisma` file location), matching the convention Prisma uses for determining output paths.

