import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 */
export function scalarToTsType(scalar: string): string {
  switch (scalar) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    case 'Decimal':
      // Decimal is represented as a string to preserve precision
      return 'string'
    default:
      return 'unknown'
  }
}

/**
 * Converts a DMMF field to its TypeScript type string.
 * Relation fields (`kind === 'object'`) are typed as `unknown`.
 */
export function fieldToTsType(field: DMMF.Field, enumNames: Set<string>): string {
  let base: string

  if (field.kind === 'scalar') {
    base = scalarToTsType(field.type)
  } else if (field.kind === 'enum') {
    base = enumNames.has(field.type) ? field.type : 'string'
  } else {
    // object (relation) or unsupported
    base = 'unknown'
  }

  if (field.isList) {
    base = `${base}[]`
  }

  return base
}

