import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { fieldToTsType } from './type-mapper'

const FILE_HEADER = '// This file was auto-generated by @prisma/rest-api-client-generator\n'

function generateModelsFile(dmmf: DMMF.Document): string {
  const lines: string[] = [FILE_HEADER]

  const enumNames = new Set(dmmf.datamodel.enums.map((e) => e.name))

  for (const enumDef of dmmf.datamodel.enums) {
    const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
    lines.push(`export type ${enumDef.name} = ${values}`)
    lines.push('')
  }

  for (const model of dmmf.datamodel.models) {
    lines.push(`export interface ${model.name} {`)
    for (const field of model.fields) {
      const tsType = fieldToTsType(field, enumNames)
      // Relation fields and optional scalars are marked optional on the interface
      const optional = !field.isRequired || field.kind === 'object' ? '?' : ''
      lines.push(`  ${field.name}${optional}: ${tsType}`)
    }
    lines.push('}')
    lines.push('')
  }

  return lines.join('\n')
}

function generateClientFile(dmmf: DMMF.Document): string {
  const lines: string[] = [FILE_HEADER]

  const enumNames = new Set(dmmf.datamodel.enums.map((e) => e.name))

  const importedNames = [
