import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

function makeDmmf(datamodel?: Partial<DMMF.Datamodel>): DMMF.Document {
  return {
    datamodel: {
      models: [],
      enums: [],
      types: [],
      indexes: [],
      ...datamodel,
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeScalarField(overrides: Partial<DMMF.Field> & Pick<DMMF.Field, 'name' | 'type'>): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

describe('generateRestClient', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-client-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  it('generates exactly three output files', async () => {
    await generateRestClient({ dmmf: makeDmmf(), outputDir: tmpDir })

    const files = await fs.readdir(tmpDir)
    expect(files.sort()).toEqual(['client.ts', 'index.ts', 'models.ts'])
  })

  it('creates outputDir when it does not exist', async () => {
    const nested = path.join(tmpDir, 'a', 'b', 'c')
    await generateRestClient({ dmmf: makeDmmf(), outputDir: nested })

    const files = await fs.readdir(nested)
    expect(files).toHaveLength(3)
  })

  it('index.ts re-exports models and client', async () => {
    await generateRestClient({ dmmf: makeDmmf(), outputDir: tmpDir })

    const content = await fs.readFile(path.join(tmpDir, 'index.ts'), 'utf-8')
    expect(content).toContain("export * from './models'")
    expect(content).toContain("export * from './client'")
  })

  describe('models.ts', () => {
    it('generates enum union types', async () => {
      const dmmf = makeDmmf({
        enums: [
          {
            name: 'Role',
            values: [
              { name: 'ADMIN', dbName: null },
              { name: 'USER', dbName: null },
            ],
            dbName: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'models.ts'), 'utf-8')
      expect(content).toContain("export type Role = 'ADMIN' | 'USER'")
    })

    it('generates model interface with required and optional scalar fields', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
              makeScalarField({ name: 'email', type: 'String', isUnique: true }),
              makeScalarField({ name: 'name', type: 'String', isRequired: false }),
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'models.ts'), 'utf-8')
      expect(content).toContain('export interface User {')
      expect(content).toContain('id: number')
      expect(content).toContain('email: string')
      expect(content).toContain('name?: string')
    })

    it('marks relation fields as optional unknown', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'String', isId: true }),
              {
                kind: 'object',
                name: 'author',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                hasDefaultValue: false,
                type: 'User',
                relationName: 'PostToUser',
                relationFromFields: ['authorId'],
                relationToFields: ['id'],
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'models.ts'), 'utf-8')
      expect(content).toContain('author?: unknown')
    })

    it('generates enum field using the enum type name', async () => {
      const dmmf = makeDmmf({
        enums: [{ name: 'Status', values: [{ name: 'ACTIVE', dbName: null }], dbName: null }],
        models: [
          {
            name: 'Item',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'String', isId: true }),
              { ...makeScalarField({ name: 'status', type: 'Status' }), kind: 'enum' },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'models.ts'), 'utf-8')
      expect(content).toContain('status: Status')
    })
  })

  describe('client.ts', () => {
    it('generates input types for each model', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [makeScalarField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
      expect(content).toContain('export interface UserCreateInput')
      expect(content).toContain('export interface UserUpdateInput')
      expect(content).toContain('export interface UserWhereUniqueInput')
      expect(content).toContain('export interface UserFindManyParams')
    })

    it('makes all fields optional in UpdateInput', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'String', isId: true }),
              makeScalarField({ name: 'title', type: 'String' }),
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
      // UpdateInput must have all fields optional
      const updateBlock = content.slice(
        content.indexOf('export interface PostUpdateInput'),
        content.indexOf('}', content.indexOf('export interface PostUpdateInput')) + 1,
      )
      expect(updateBlock).toContain('id?:')
      expect(updateBlock).toContain('title?:')
    })

    it('makes defaultValue fields optional in CreateInput', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
              makeScalarField({ name: 'title', type: 'String' }),
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
      const createBlock = content.slice(
        content.indexOf('export interface PostCreateInput'),
        content.indexOf('}', content.indexOf('export interface PostCreateInput')) + 1,
      )
      expect(createBlock).toContain('id?:')
      expect(createBlock).toContain('title:')
    })

    it('generates all five CRUD methods per model', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [makeScalarField({ name: 'id', type: 'String', isId: true })],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
      expect(content).toContain('export class PrismaRestApiClient')
      expect(content).toContain('findManyPost(')
      expect(content).toContain('findUniquePost(')
      expect(content).toContain('createPost(')
      expect(content).toContain('updatePost(')
      expect(content).toContain('deletePost(')
    })

    it('uses the model name (camelCase) as the REST resource path', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'BlogPost',
            dbName: null,
            schema: null,
            fields: [makeScalarField({ name: 'id', type: 'String', isId: true })],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
      await generateRestClient({ dmmf, outputDir: tmpDir })

      const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
      expect(content).toContain("'POST', '/blogPost'")
    })

    it('skips relation fields in CreateInput and UpdateInput', async () => {
      const dmmf = makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              makeScalarField({ name: 'id', type: 'String', isId: true }),
              {
                kind: 'object',
                name: 'author',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                hasDefaultValue: false,
                type: 'User',
                relationName: 'PostToUser',
                relationFromFields: ['authorId'],
                relationToFields: ['id'],
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      })
